parameters.jsCode:
const payload = $input.first().json.payload ?? $input.first().json;

// ── Helper: safely dig into nested objects ──────────────────────────
function get(obj, ...keys) {
  return keys.reduce((o, k) => (o != null ? o[k] : undefined), obj);
}

// ── Helper: search Q&A array by keyword ────────────────────────────
function findAnswer(qna, keyword) {
  if (!Array.isArray(qna)) return '';
  const match = qna.find(q =>
    (q.question ?? '').toLowerCase().includes(keyword.toLowerCase())
  );
  return match?.answer ?? '';
}

// ── Invitee details ─────────────────────────────────────────────────
const fullName =
  get(payload, 'name') ??
  get(payload, 'invitee', 'name') ??
  get(payload, 'full_name') ?? '';

const email =
  get(payload, 'email') ??
  get(payload, 'invitee', 'email') ?? '';

const firstName =
  get(payload, 'first_name') ??
  get(payload, 'invitee', 'first_name') ??
  fullName.split(' ')[0] ?? '';

const lastName =
  get(payload, 'last_name') ??
  get(payload, 'invitee', 'last_name') ??
  fullName.split(' ').slice(1).join(' ') ?? '';

const cancelUrl =
  get(payload, 'cancel_url') ??
  get(payload, 'invitee', 'cancel_url') ?? '';

const rescheduleUrl =
  get(payload, 'reschedule_url') ??
  get(payload, 'invitee', 'reschedule_url') ?? '';

// ── Q&A ─────────────────────────────────────────────────────────────
const qna =
  get(payload, 'questions_and_answers') ??
  get(payload, 'invitee', 'questions_and_answers') ??
  get(payload, 'form_submission', 'answers') ?? [];

const inviteeOrg   = findAnswer(qna, 'company') || findAnswer(qna, 'organization') || findAnswer(qna, 'org');
const inviteePhone = findAnswer(qna, 'phone')   || findAnswer(qna, 'mobile')       || findAnswer(qna, 'contact');

// ── Event / scheduled details ───────────────────────────────────────
const event =
  get(payload, 'scheduled_event') ??
  get(payload, 'event') ?? {};

const eventTypeName =
  get(event, 'name') ??
  get(payload, 'event_type', 'name') ??
  get(payload, 'event_type_name') ?? 'Sales Call';

const startTime =
  get(event, 'start_time') ??
  get(payload, 'start_time') ?? new Date().toISOString();

const startTimeFormatted = new Date(startTime).toLocaleString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  timeZoneName: 'short'
});

// ── Meeting join URL ────────────────────────────────────────────────
const location = get(event, 'location') ?? get(payload, 'location') ?? {};
const meetingJoinUrl =
  get(location, 'join_url') ??
  get(location, 'data') ??
  get(location, 'url') ??
  get(event,    'join_url') ??
  'See your calendar invite for the meeting link';

// ── Due date for ClickUp task (2 hrs before meeting) ────────────────
const taskDueDateMs = new Date(startTime).getTime() - (2 * 60 * 60 * 1000);

// ── Reminder timestamps ─────────────────────────────────────────────
const reminder24hAt = new Date(new Date(startTime).getTime() - 24 * 60 * 60 * 1000).toISOString();
const reminder1hAt  = new Date(new Date(startTime).getTime() -  1 * 60 * 60 * 1000).toISOString();

// ── Output ──────────────────────────────────────────────────────────
return [{
  json: {
    inviteeName:        fullName,
    inviteeEmail:       email,
    firstName,
    lastName,
    inviteeOrg,
    inviteePhone,
    eventTypeName,
    startTime,
    startTimeFormatted,
    meetingJoinUrl,
    cancelUrl,
    rescheduleUrl,
    dealName:           `${fullName} — ${eventTypeName}`,
    taskDueDateMs,
    reminder24hAt,
    reminder1hAt,
    _raw: payload
  }
}];
